#include <bits/stdc++.h>
using namespace std;
#define int long long

const int N = 2e5 + 5;

int fa[N], sz[N], deg[N], d[N], vis[N];
vector<int> e[N], s;

int find(int x) {
    return fa[x] == x ? x : fa[x] = find(fa[x]);
}

void merge(int x, int y) {
    x = find(x), y = find(y);
    if (x == y) return;
    if (sz[x] > sz[y]) swap(x, y);
    fa[x] = y;
    sz[y] += sz[x];
}

signed main() {
    int n, m, ans = 0; 
    cin >> n >> m;
    for (int i = 1; i <= n; i++) {
        fa[i] = i;
        sz[i] = 1;
    }
    for (int i = 1; i <= m; i++) {
        int u, v;
        cin >> u >> v;
        e[u].push_back(v);
        e[v].push_back(u);
        deg[u]++;
        deg[v]++;
    }
    set<pair<int, int>> q;
    for (int i = 1; i <= n; i++) {
        q.insert({deg[i], i});
    }
    while (!q.empty()) {
        int u = q.begin()->second;
        q.erase(q.begin());
        d[u] = deg[u];
        s.push_back(u);
        for (int v : e[u]) {
            if (d[v]) continue;
            q.erase({deg[v], v});
            deg[v]--;
            q.insert({deg[v], v});
        }
    }
    reverse(s.begin(), s.end());
    for (int x : s) {
        vis[x] = 1;
        int cnt = 0;
        for (int v : e[x]) {
            if (vis[v]) {
                cnt++;
                merge(x, v);
            }
        }
        d[x] = cnt; 
        ans = max(ans, d[x] * sz[find(x)]);
    }
    cout << ans << endl;
    return 0;
}
